import * as fs from 'fs';
import * as path from 'path';

const formalPath = path.join(process.cwd(), 'open-source/aeon/FORMAL_LEDGER.md');
const ownershipPath = path.join(process.cwd(), 'open-source/gnosis/scripts/ledger-mcp-ownership.ts');

const formalText = fs.readFileSync(formalPath, 'utf8');
const ownershipSource = fs.readFileSync(ownershipPath, 'utf8');

const map = new Map<string, string[]>();
let cur = '';

for (const line of formalText.split('\n')) {
  if (line.startsWith('## ') || line.startsWith('### ')) {
    cur = line.replace(/^###?\s+/, '').trim();
    map.set(cur, []);
  } else if (cur) {
    if (line.match(/\|\s+\`THM-/)) map.get(cur)?.push(line);
  }
}

const missing = [];
for (const [sec, lines] of map.entries()) {
  const normSec = sec.replace(/\s*\([^)]*\)\s*/g, ' ').replace(/\s+/g, ' ').trim();
  if (!ownershipSource.includes(normSec)) {
    missing.push({ section: normSec, original: sec, count: lines.length });
  }
}

fs.writeFileSync('/tmp/missing_ownership.json', JSON.stringify(missing, null, 2));
console.log('Missing ownerships:', missing.length);
